const files = $input.all().map(item => item.json);
const today = new Date().toISOString().split('T')[0].replace(/-/g, '');

const fileTypes = [
  { pattern: `patients_${today}.csv`, type: 'Patient' },
  { pattern: `conditions_${today}.csv`, type: 'Condition' },
  { pattern: `meds_${today}.csv`, type: 'MedicationRequest' },
  { pattern: `labs_${today}.csv`, type: 'Observation' },
  { pattern: `encounters_${today}.csv`, type: 'Encounter' }
];

const matchedFiles = files
  .filter(file => fileTypes.some(ft => file.name === ft.pattern))
  .map(file => {
    const fileType = fileTypes.find(ft => ft.pattern === file.name);
    return {
      json: {
        ...file,
        resourceType: fileType.type,
        fullPath: `/exports/hdim/${file.name}`
      }
    };
  });

if (matchedFiles.length === 0) {
  throw new Error(`No export files found for date ${today}`);
}

return matchedFiles;

const row = $input.item.json;

const patient = {
  resourceType: 'Patient',
  id: row.MRN,
  meta: {
    source: 'Meditech Expanse via n8n',
    lastUpdated: new Date().toISOString()
  },
  identifier: [
    {
      use: 'usual',
      type: {
        coding: [{
          system: 'http://terminology.hl7.org/CodeSystem/v2-0203',
          code: 'MR'
        }]
      },
      system: 'http://mountainviewcah.org/mrn',
      value: row.MRN
    }
  ],
  active: true,
  name: [
    {
      use: 'official',
      family: row.PATIENT_NAME.split(' ')[0],
      given: row.PATIENT_NAME.split(' ').slice(1)
    }
  ],
  gender: row.GENDER === 'M' ? 'male' : row.GENDER === 'F' ? 'female' : 'unknown',
  birthDate: row.DOB
};

// Add phone if present
if (row.PHONE) {
  patient.telecom = [{
    system: 'phone',
    value: row.PHONE,
    use: 'home'
  }];
}

// Add address if present
if (row.ADDRESS) {
  patient.address = [{
    use: 'home',
    line: [row.ADDRESS],
    city: row.CITY,
    state: row.STATE,
    postalCode: row.ZIP
  }];
}

return { json: patient };

const row = $input.item.json;

const condition = {
  resourceType: 'Condition',
  id: `mv-cond-${row.MRN}-${row.ICD_CODE.replace(/\./g, '')}`,
  meta: {
    source: 'Meditech Expanse via n8n',
    lastUpdated: new Date().toISOString()
  },
  clinicalStatus: {
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/condition-clinical',
      code: row.STATUS === 'ACTIVE' ? 'active' : 'resolved'
    }]
  },
  verificationStatus: {
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/condition-ver-status',
      code: 'confirmed'
    }]
  },
  category: [{
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/condition-category',
      code: 'problem-list-item'
    }]
  }],
  code: {
    coding: [{
      system: 'http://hl7.org/fhir/sid/icd-10-cm',
      code: row.ICD_CODE,
      display: row.DIAGNOSIS_NAME
    }],
    text: row.DIAGNOSIS_NAME
  },
  subject: {
    reference: `Patient/${row.MRN}`
  },
  onsetDateTime: row.ONSET_DATE,
  recordedDate: row.RECORDED_DATE
};

return { json: condition };

const row = $input.item.json;

const medication = {
  resourceType: 'MedicationRequest',
  id: `mv-med-${row.MRN}-${row.MED_ID}`,
  meta: {
    source: 'Meditech Expanse via n8n',
    lastUpdated: new Date().toISOString()
  },
  status: row.STATUS === 'ACTIVE' ? 'active' : 'stopped',
  intent: 'order',
  medicationCodeableConcept: {
    coding: row.NDC ? [{
      system: 'http://hl7.org/fhir/sid/ndc',
      code: row.NDC,
      display: row.MED_NAME
    }] : [],
    text: row.MED_NAME
  },
  subject: {
    reference: `Patient/${row.MRN}`
  },
  authoredOn: row.START_DATE,
  dosageInstruction: [{
    text: row.SIG || `${row.DOSE} ${row.ROUTE} ${row.FREQUENCY}`,
    timing: {
      code: {
        text: row.FREQUENCY
      }
    },
    route: {
      text: row.ROUTE
    },
    doseAndRate: [{
      doseQuantity: {
        value: parseFloat(row.DOSE) || null,
        unit: row.DOSE_UNIT
      }
    }]
  }]
};

return { json: medication };

const row = $input.item.json;

// Map common Meditech lab codes to LOINC
const loincMap = {
  'HBA1C': '4548-4',
  'GLUCOSE': '2345-7',
  'BUN': '3094-0',
  'CREAT': '2160-0',
  'NA': '2951-2',
  'K': '2823-3',
  'CL': '2075-0',
  'CO2': '2028-9',
  'WBC': '26464-8',
  'RBC': '789-8',
  'HGB': '718-7',
  'HCT': '4544-3',
  'PLT': '777-3',
  'MCV': '787-2',
  'CHOL': '2093-3',
  'TRIG': '2571-8',
  'HDL': '2085-9',
  'LDL': '2089-1'
};

const loincCode = loincMap[row.TEST_CODE] || row.TEST_CODE;

const observation = {
  resourceType: 'Observation',
  id: `mv-lab-${row.MRN}-${row.TEST_CODE}-${row.RESULT_DATE.replace(/-/g, '')}`,
  meta: {
    source: 'Meditech Expanse via n8n',
    lastUpdated: new Date().toISOString()
  },
  status: row.STATUS === 'F' ? 'final' : 'preliminary',
  category: [{
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/observation-category',
      code: 'laboratory'
    }]
  }],
  code: {
    coding: [{
      system: 'http://loinc.org',
      code: loincCode,
      display: row.TEST_NAME
    }],
    text: row.TEST_NAME
  },
  subject: {
    reference: `Patient/${row.MRN}`
  },
  effectiveDateTime: row.RESULT_DATE
};

// Handle numeric vs string results
const numValue = parseFloat(row.RESULT);
if (!isNaN(numValue)) {
  observation.valueQuantity = {
    value: numValue,
    unit: row.UNIT || '',
    system: 'http://unitsofmeasure.org',
    code: row.UNIT || ''
  };

  // Add reference range if available
  if (row.REF_LOW || row.REF_HIGH) {
    observation.referenceRange = [{
      low: row.REF_LOW ? { value: parseFloat(row.REF_LOW), unit: row.UNIT } : undefined,
      high: row.REF_HIGH ? { value: parseFloat(row.REF_HIGH), unit: row.UNIT } : undefined
    }];
  }

  // Add interpretation
  if (row.ABNORMAL_FLAG === 'H') {
    observation.interpretation = [{
      coding: [{ system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation', code: 'H', display: 'High' }]
    }];
  } else if (row.ABNORMAL_FLAG === 'L') {
    observation.interpretation = [{
      coding: [{ system: 'http://terminology.hl7.org/CodeSystem/v3-ObservationInterpretation', code: 'L', display: 'Low' }]
    }];
  }
} else {
  observation.valueString = row.RESULT;
}

return { json: observation };

const row = $input.item.json;

// Map admit types to FHIR class codes
const classMap = {
  'EMERGENCY': { code: 'EMER', display: 'emergency' },
  'ELECTIVE': { code: 'IMP', display: 'inpatient encounter' },
  'URGENT': { code: 'EMER', display: 'emergency' },
  'OBSERVATION': { code: 'OBSENC', display: 'observation encounter' },
  'OUTPATIENT': { code: 'AMB', display: 'ambulatory' }
};

// Map discharge dispositions
const dispMap = {
  'HOME': { code: 'home', display: 'Home' },
  'SNF': { code: 'snf', display: 'Skilled nursing facility' },
  'REHAB': { code: 'rehab', display: 'Rehabilitation' },
  'AMA': { code: 'aadvice', display: 'Left against advice' },
  'EXPIRED': { code: 'exp', display: 'Expired' },
  'TRANSFER': { code: 'other-hcf', display: 'Other healthcare facility' }
};

const encounterClass = classMap[row.ADMIT_TYPE] || { code: 'IMP', display: 'inpatient encounter' };
const disposition = dispMap[row.DISCHARGE_DISP] || { code: 'oth', display: 'Other' };

const encounter = {
  resourceType: 'Encounter',
  id: `mv-enc-${row.MRN}-${row.ADMIT_DATE.replace(/-/g, '')}`,
  meta: {
    source: 'Meditech Expanse via n8n',
    lastUpdated: new Date().toISOString()
  },
  status: row.DISCHARGE_DATE ? 'finished' : 'in-progress',
  class: {
    system: 'http://terminology.hl7.org/CodeSystem/v3-ActCode',
    code: encounterClass.code,
    display: encounterClass.display
  },
  type: [{
    coding: [{
      system: 'http://terminology.hl7.org/CodeSystem/encounter-type',
      code: row.ADMIT_TYPE.toLowerCase(),
      display: row.ADMIT_TYPE
    }]
  }],
  subject: {
    reference: `Patient/${row.MRN}`,
    display: row.PATIENT_NAME
  },
  period: {
    start: row.ADMIT_DATE,
    end: row.DISCHARGE_DATE || undefined
  }
};

// Add diagnosis if present
if (row.PRIMARY_DX) {
  encounter.diagnosis = [{
    condition: {
      reference: `Condition/mv-cond-${row.MRN}-${row.PRIMARY_DX.replace(/\./g, '')}`
    },
    use: {
      coding: [{
        system: 'http://terminology.hl7.org/CodeSystem/diagnosis-role',
        code: 'billing'
      }]
    },
    rank: 1
  }];
}

// Add length of stay if discharged
if (row.LOS && row.DISCHARGE_DATE) {
  encounter.length = {
    value: parseInt(row.LOS),
    unit: 'days',
    system: 'http://unitsofmeasure.org',
    code: 'd'
  };

  encounter.hospitalization = {
    dischargeDisposition: {
      coding: [{
        system: 'http://terminology.hl7.org/CodeSystem/discharge-disposition',
        code: disposition.code,
        display: disposition.display
      }]
    }
  };
}

return { json: encounter };

const resources = $input.all().map(item => item.json);

// Group resources by type for ordered processing
const grouped = {
  Patient: [],
  Condition: [],
  MedicationRequest: [],
  Observation: [],
  Encounter: []
};

resources.forEach(resource => {
  if (grouped[resource.resourceType]) {
    grouped[resource.resourceType].push(resource);
  }
});

// Create ordered entries (Patients first, then dependent resources)
const orderedResources = [
  ...grouped.Patient,
  ...grouped.Condition,
  ...grouped.MedicationRequest,
  ...grouped.Observation,
  ...grouped.Encounter
];

// Split into batches of 100
const BATCH_SIZE = 100;
const batches = [];

for (let i = 0; i < orderedResources.length; i += BATCH_SIZE) {
  const batchResources = orderedResources.slice(i, i + BATCH_SIZE);

  const bundle = {
    resourceType: 'Bundle',
    type: 'batch',
    timestamp: new Date().toISOString(),
    entry: batchResources.map(resource => ({
      fullUrl: `urn:uuid:${resource.id}`,
      resource: resource,
      request: {
        method: 'PUT',
        url: `${resource.resourceType}/${resource.id}`
      }
    }))
  };

  batches.push({ json: bundle });
}

console.log(`Created ${batches.length} bundles from ${orderedResources.length} resources`);
return batches;

// Get list of processed files from earlier in workflow
const processedFiles = $('Filter Today\'s Files').all().map(item => item.json);

const archiveDate = new Date().toISOString().split('T')[0];

return processedFiles.map(file => ({
  json: {
    originalPath: file.fullPath,
    archivePath: `/exports/hdim/archive/${archiveDate}/${file.name}`,
    fileName: file.name,
    resourceType: file.resourceType
  }
}));
